type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };

const PROCESSING_FEE = 5;
const BLOCK_SIZE = 3;
const BLOCK_DISCOUNT = 15;

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const TYPES_WITH_BLOCK_DISCOUNT = new Set(["rune"]);

const basePremiumFor = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type];

const groupCountsByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const baseForType = (type: string, count: number): number => {
  const unitPrice = BASE_PREMIUM_BY_TYPE[type];
  const isBlockEligible = TYPES_WITH_BLOCK_DISCOUNT.has(type) && count === BLOCK_SIZE;
  return count * unitPrice - (isBlockEligible ? BLOCK_DISCOUNT : 0);
};

const quoteStep = (step: QuoteStep): { premium: number } => {
  const counts = groupCountsByType(step.items);
  let itemsBase = 0;
  for (const [type, count] of counts) {
    itemsBase += baseForType(type, count);
  }
  return { premium: itemsBase + PROCESSING_FEE };
};

export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
  return { results: scenario.steps.map(quoteStep) };
};

